import{_ as e,o as a,c as s,ag as o}from"./chunks/framework.DL0AyVxm.js";const p=JSON.parse('{"title":"Slash Commands","description":"","frontmatter":{},"headers":[],"relativePath":"reference/slash-commands.md","filePath":"reference/slash-commands.md"}'),d={name:"reference/slash-commands.md"};function r(n,t,i,c,l,h){return a(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="slash-commands" tabindex="-1">Slash Commands <a class="header-anchor" href="#slash-commands" aria-label="Permalink to &quot;Slash Commands&quot;">​</a></h1><p>Worclaude installs 10 slash commands as Markdown files in <code>.claude/commands/</code>. These are invoked inside a Claude Code session by typing the command name (e.g., <code>/start</code>). Each command gives Claude a specific instruction set for that task.</p><h2 id="command-reference" tabindex="-1">Command Reference <a class="header-anchor" href="#command-reference" aria-label="Permalink to &quot;Command Reference&quot;">​</a></h2><h3 id="start" tabindex="-1">/start <a class="header-anchor" href="#start" aria-label="Permalink to &quot;/start&quot;">​</a></h3><p><strong>Session kickoff.</strong> Orients Claude at the beginning of a work session.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/start.md</code></td></tr><tr><td><strong>When to use</strong></td><td>At the start of every Claude Code session</td></tr><tr><td><strong>What it does</strong></td><td>Reads <code>docs/spec/PROGRESS.md</code> to understand project state. Reads the active implementation prompt if one exists. Reports what was last completed, what is next, and any blockers.</td></tr><tr><td><strong>Key behavior</strong></td><td>Read-only. Does not modify files.</td></tr></tbody></table><hr><h3 id="end" tabindex="-1">/end <a class="header-anchor" href="#end" aria-label="Permalink to &quot;/end&quot;">​</a></h3><p><strong>Session wrapdown.</strong> Ensures clean session endings with proper state persistence.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/end.md</code></td></tr><tr><td><strong>When to use</strong></td><td>When finishing a work session</td></tr><tr><td><strong>What it does</strong></td><td>Updates <code>docs/spec/PROGRESS.md</code> with completed items, in-progress work, blockers, and next steps. If ending mid-task, writes a handoff document at <code>docs/handoffs/HANDOFF_{date}.md</code> with enough context for seamless continuation.</td></tr><tr><td><strong>Key behavior</strong></td><td>Always commits working code before updating PROGRESS.md.</td></tr></tbody></table><hr><h3 id="commit-push-pr" tabindex="-1">/commit-push-pr <a class="header-anchor" href="#commit-push-pr" aria-label="Permalink to &quot;/commit-push-pr&quot;">​</a></h3><p><strong>Full git workflow.</strong> Stages, commits, pushes, and opens a pull request in one flow.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/commit-push-pr.md</code></td></tr><tr><td><strong>When to use</strong></td><td>When a feature or fix is ready for review</td></tr><tr><td><strong>What it does</strong></td><td>Stages all changes with <code>git add -A</code>. Writes a clear conventional commit message. Pushes to the current branch. Creates a PR with <code>gh pr create</code> including title, description, testing notes, and reviewer guidance.</td></tr><tr><td><strong>Key behavior</strong></td><td>Uses <code>gh</code> CLI for PR creation.</td></tr></tbody></table><hr><h3 id="review-plan" tabindex="-1">/review-plan <a class="header-anchor" href="#review-plan" aria-label="Permalink to &quot;/review-plan&quot;">​</a></h3><p><strong>Plan review with the plan-reviewer agent.</strong> Sends an implementation plan through a senior staff engineer review.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/review-plan.md</code></td></tr><tr><td><strong>When to use</strong></td><td>After writing an implementation plan, before starting implementation</td></tr><tr><td><strong>What it does</strong></td><td>Sends the current plan to the <code>plan-reviewer</code> agent (Opus). The reviewer checks for ambiguity, missing verification steps, unrealistic scope, edge cases, and SPEC.md alignment.</td></tr><tr><td><strong>Key behavior</strong></td><td>Blocks implementation until all feedback is addressed. The plan should be updated with revisions before proceeding.</td></tr></tbody></table><hr><h3 id="techdebt" tabindex="-1">/techdebt <a class="header-anchor" href="#techdebt" aria-label="Permalink to &quot;/techdebt&quot;">​</a></h3><p><strong>Technical debt scan.</strong> Identifies code quality issues across the codebase.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/techdebt.md</code></td></tr><tr><td><strong>When to use</strong></td><td>Periodically, or when the codebase feels messy</td></tr><tr><td><strong>What it does</strong></td><td>Scans for duplicated code, dead code (unused functions, imports, variables), TODO/FIXME/HACK comments, overly complex functions, missing tests for critical paths, and inconsistent patterns. Reports findings by severity. Fixes quick wins directly.</td></tr><tr><td><strong>Key behavior</strong></td><td>Produces a prioritized report. Small fixes are applied immediately; larger items are documented.</td></tr></tbody></table><hr><h3 id="verify" tabindex="-1">/verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;/verify&quot;">​</a></h3><p><strong>Run verification suite.</strong> Full project validation across all check types.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/verify.md</code></td></tr><tr><td><strong>When to use</strong></td><td>Before committing, before opening a PR, after major changes</td></tr><tr><td><strong>What it does</strong></td><td>Runs the test suite, build, linter, and type checker (if applicable). Runs domain-specific verification as needed. Reports results clearly.</td></tr><tr><td><strong>Key behavior</strong></td><td>Blocks further work if any check fails. All checks must pass before proceeding.</td></tr></tbody></table><hr><h3 id="compact-safe" tabindex="-1">/compact-safe <a class="header-anchor" href="#compact-safe" aria-label="Permalink to &quot;/compact-safe&quot;">​</a></h3><p><strong>Safe context compaction.</strong> Compresses context while preserving orientation.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/compact-safe.md</code></td></tr><tr><td><strong>When to use</strong></td><td>When context is running low (~70% used) and you need to keep working</td></tr><tr><td><strong>What it does</strong></td><td>Triggers <code>/compact</code> to compress conversation history. The PostCompact hook automatically re-reads CLAUDE.md and PROGRESS.md. After compaction, Claude confirms the current task, current branch, and what was being worked on.</td></tr><tr><td><strong>Key behavior</strong></td><td>Relies on the PostCompact hook for automatic context re-injection. See <a href="/Worclaude/reference/hooks.html">Hooks</a>.</td></tr></tbody></table><hr><h3 id="status" tabindex="-1">/status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;/status&quot;">​</a></h3><p><strong>Session status check.</strong> Reports current session state without modifying anything.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/status.md</code></td></tr><tr><td><strong>When to use</strong></td><td>Mid-session to check where things stand</td></tr><tr><td><strong>What it does</strong></td><td>Reports the current task, git branch and recent commits, test status from the last run, context usage estimate, and any blockers or pending decisions.</td></tr><tr><td><strong>Key behavior</strong></td><td>Read-only. This is a session-level status check, distinct from the <code>worclaude status</code> CLI command which reports installation metadata.</td></tr></tbody></table><hr><h3 id="update-claude-md" tabindex="-1">/update-claude-md <a class="header-anchor" href="#update-claude-md" aria-label="Permalink to &quot;/update-claude-md&quot;">​</a></h3><p><strong>Update CLAUDE.md rules.</strong> Proposes self-healing rule additions based on session experience.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/update-claude-md.md</code></td></tr><tr><td><strong>When to use</strong></td><td>At session end, or after encountering a repeated mistake</td></tr><tr><td><strong>What it does</strong></td><td>Reviews what happened during the session. Identifies mistakes that should become rules, patterns worth documenting, and gotchas encountered. Writes proposed additions to the Gotchas or Critical Rules section. Shows the diff before applying.</td></tr><tr><td><strong>Key behavior</strong></td><td>Never applies changes without showing a diff first. Follows the self-healing pattern described in the <a href="/Worclaude/reference/skills.html">claude-md-maintenance skill</a>.</td></tr></tbody></table><hr><h3 id="setup" tabindex="-1">/setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;/setup&quot;">​</a></h3><p><strong>Project interview to fill specs.</strong> Conducts a structured interview and populates all project-specific files.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/commands/setup.md</code></td></tr><tr><td><strong>When to use</strong></td><td>Once, after initial <code>worclaude init</code>, to configure the project</td></tr><tr><td><strong>What it does</strong></td><td>Runs a 7-section interview: Project Story, Architecture &amp; Structure, Tech Stack Details, Core Features, Development Workflow, Coding Conventions, Verification Strategy. Users can type &quot;skip&quot; or &quot;back&quot; at any point.</td></tr><tr><td><strong>Key behavior</strong></td><td>After the interview, updates 6 files with real project content: CLAUDE.md (tech stack and commands), SPEC.md (full specification), backend-conventions.md, frontend-design-system.md, project-patterns.md, and PROGRESS.md.</td></tr></tbody></table><p><strong>Interview sections:</strong></p><table tabindex="0"><thead><tr><th>Section</th><th>Topics Covered</th></tr></thead><tbody><tr><td>1. Project Story</td><td>Purpose, users, problem it solves, existing docs or PRDs</td></tr><tr><td>2. Architecture &amp; Structure</td><td>Architecture type, directory layout, database, external services, deployment</td></tr><tr><td>3. Tech Stack Details</td><td>Frameworks and versions, package manager, ORM, testing tools, linting</td></tr><tr><td>4. Core Features</td><td>Main features, built vs planned, priority order, business logic, edge cases</td></tr><tr><td>5. Development Workflow</td><td>Start commands, test commands, build commands, env vars, CI/CD, setup steps</td></tr><tr><td>6. Coding Conventions</td><td>Design patterns, error handling, logging, API format, naming, project rules</td></tr><tr><td>7. Verification Strategy</td><td>Verification approach, test commands, manual testing, browser testing, CI checks</td></tr></tbody></table><hr><h2 id="command-file-location" tabindex="-1">Command File Location <a class="header-anchor" href="#command-file-location" aria-label="Permalink to &quot;Command File Location&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/commands/</span></span>
<span class="line"><span>  start.md</span></span>
<span class="line"><span>  end.md</span></span>
<span class="line"><span>  commit-push-pr.md</span></span>
<span class="line"><span>  review-plan.md</span></span>
<span class="line"><span>  techdebt.md</span></span>
<span class="line"><span>  verify.md</span></span>
<span class="line"><span>  compact-safe.md</span></span>
<span class="line"><span>  status.md</span></span>
<span class="line"><span>  update-claude-md.md</span></span>
<span class="line"><span>  setup.md</span></span></code></pre></div><p>Commands can be customized after installation. Additional custom commands can be added to the same directory.</p><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/Worclaude/reference/agents.html">Agents</a> -- agents invoked by commands (e.g., <code>/review-plan</code> uses <code>plan-reviewer</code>)</li><li><a href="/Worclaude/reference/skills.html">Skills</a> -- knowledge loaded by commands (e.g., <code>/end</code> follows <code>review-and-handoff</code>)</li><li><a href="/Worclaude/reference/hooks.html">Hooks</a> -- hooks triggered by commands (e.g., <code>/compact-safe</code> triggers PostCompact)</li></ul>`,51)])])}const u=e(d,[["render",r]]);export{p as __pageData,u as default};
